mapper.select:
SELECT COUNT(1)
FROM talent_tag
WHERE enterprise_id = #{enterpriseId}
  AND tag_name = #{tagName}

    AND id <> #{excludeId}

mapper.update:
UPDATE talent_tag
SET tag_name = #{tagName},
    tag_color = #{tagColor},
    description = #{description},
    sort_order = #{sortOrder}
WHERE id = #{id}
  AND enterprise_id = #{enterpriseId}

mapper.delete:
DELETE
FROM talent_tag
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
